  ('bookkeeper-moex-01064', 'bookkeeper', 'bookkeeper-moex-106-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '依商業會計處理準則之規定，有關應收帳款之處理，下列敘述何者正確？ 金額重大之應收關係人帳款，不應單獨列示 已提供擔保者，不應予揭露 分期付款銷貨之未實現利息收入，應列為應收帳款之加項 業已確定無法收回者，應予轉銷', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "c473f73014d0", "answer_pdf_sha1": "8e580acee728", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "602", "s": "1202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 32, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
