  ('bookkeeper-moex-01067', 'bookkeeper', 'bookkeeper-moex-106-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '依行政程序法規定，有關行政處分效力之敘述，下列何者錯誤？ 無效之行政處分自始不生效力 行政處分一部分無效者，其他部分仍為有效 除去無效部分，行政處分不能成立者，則全部無效 行政處分之無效，行政機關不得依職權確認之', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "c473f73014d0", "answer_pdf_sha1": "8e580acee728", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "602", "s": "1202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 35, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
