  ('bookkeeper-moex-01071', 'bookkeeper', 'bookkeeper-moex-106-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '丙商行辦理商業登記文件，涉有偽造、變造情形，若經法院判處不起訴處分、緩起訴處分確定或為無罪、 免訴、不受理、不付審理、不付保護處分、免刑、緩刑之裁判確定者等情形，依商業登記法第29條第1 項第1款及商業登記法第30條規定，下列何者正確？ 撤銷或廢止其登記 停止營業一個月 不符第29條第1項第1款撤銷或廢止其登記之規定，也不適用第30條登記事項虛偽情事之行政罰 不符第29條第1項第1款撤銷或廢止其登記之規定，得適用第30條登記事項虛偽情事之行政罰', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "c473f73014d0", "answer_pdf_sha1": "8e580acee728", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "602", "s": "1202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 39, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL)
